import React, { useEffect, useState } from "react";

const Users = () => {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const fetchUsers = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem("adminToken");

      const res = await fetch("http://localhost:5000/api/admin/users", {
        headers: { Authorization: `Bearer ${token}` },
      });

      const data = await res.json();

      if (data.success && Array.isArray(data.data)) {
        setUsers(data.data);
      } else {
        setError("Dữ liệu không hợp lệ từ server");
      }
    } catch (err) {
      console.error(err);
      setError("Không thể tải danh sách người dùng");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUsers();
  }, []);

  if (loading) return <p>⏳ Đang tải...</p>;
  if (error) return <p>❌ {error}</p>;

  return (
    <div>
      <h1 className="text-2xl font-bold text-[#e06c7f] mb-4">👤 Quản lý người dùng</h1>

      <table className="w-full text-left border">
        <thead>
          <tr className="bg-[#fdecef] text-[#e06c7f]">
            <th className="p-2">Tên</th>
            <th className="p-2">Email</th>
            <th className="p-2">Role</th>
            <th className="p-2">Ngày tạo</th>
          </tr>
        </thead>
        <tbody>
          {users.map((u) => (
            <tr key={u._id} className="border-b hover:bg-[#f9ecef]">
              <td className="p-2">{u.name}</td>
              <td className="p-2">{u.email}</td>
              <td className="p-2">{u.role}</td>
              <td className="p-2">{new Date(u.createdAt).toLocaleDateString("vi-VN")}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default Users;
